                    @foreach (var channel in _allChannels)
                    {
                        var isMuted = _editMutedChannels.Contains(channel);
                        <label class="list-group-item d-flex align-items-center gap-2">
                            <input class="form-check-input" type="checkbox"
                                   checked="@isMuted"
                                   @onchange="e => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                            <span>@channel</span>
                            @if (isMuted)
                            {
                                <span class="badge bg-secondary ms-auto">Muted</span>
                            }
                        </label>
                    }
                </div>
            }

            <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </section>;
}

@* ───── Security Section ───── *@
@{
    RenderFragment RenderSecuritySection() =>
        @<section>
            <h2 class="section-title">Security</h2>

            <!-- Change Password -->
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between align-items-center"
                     role="button"
                     @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span class="fw-semibold">Change Password</span>
                    <span class="chevron @(_passwordPanelOpen ? "open" : "")">▸</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="card-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        @if (_passwordError is not null)
                        {
                            <div class="alert alert-danger py-2">@_passwordError</div>
                        }
                        <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="setting-row mb-4">
                <div>
                    <div class="fw-semibold">Two-Factor Authentication</div>
                    <div class="d-flex align-items-center gap-2 mt-1">
                        <span class="status-dot @(_twoFactorEnabled ? "status-on" : "status-off")"></span>
                        <small>@(_twoFactorEnabled ? "Enabled" : "Disabled")</small>
                    </div>
                    @if (_lastPasswordChange.HasValue)
                    {
                        <small class="text-muted d-block mt-1">
                            Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
                        </small>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>

            <!-- Active Sessions -->
            <h5 class="mb-3">Active Sessions</h5>
            @if (_sessions.Count == 0)
            {
                <p class="text-muted">No active sessions.</p>
            }
            else
            {
                <div class="table-responsive">
                    <table class="table table-hover align-middle">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _sessions)
                            {
                                var isCurrentSession = session == _sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrentSession)
                                        {
                                            <span class="badge bg-success ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("MMM d, yyyy h:mm tt")</td>
                                    <td>
                                        @if (!isCurrentSession)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }

            <!-- Revoke Confirmation Dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop show"></div>
                <div class="modal d-block" tabindex="-1" role="dialog">
                    <div class="modal-dialog modal-dialog-centered" role="document">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h5 class="modal-title">Revoke Session</h5>
                                <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                            </div>
                            <div class="modal-body">
                                <p>
                                    Are you sure you want to revoke the session on
                                    <strong>@_sessionToRevoke.Device</strong> in
                                    <strong>@_sessionToRevoke.Location</strong>?
                                </p>
                            </div>
                            <div class="modal-footer">
                                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                                <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_saving">
                                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                    Revoke
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        </section>;
}

@* ───── Appearance Section ───── *@
@{
    RenderFragment RenderAppearanceSection() =>
        @<section>
            <h2 class="section-title">Appearance</h2>

            <!-- Theme -->
            <div class="mb-4">
                <label class="form-label fw-semibold">Theme</label>
                <div class="d-flex gap-3">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="theme-@theme" value="@theme"
                                   checked="@(_editTheme == theme)"
                                   @onchange="() => _editTheme = theme" />
                            <label class="form-check-label" for="theme-@theme">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Font Size -->
            <div class="mb-4">
                <label class="form-label fw-semibold">Font Size</label>
                <div class="d-flex gap-3">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="font-@size" value="@size"
                                   checked="@(_editFontSize == size)"
                                   @onchange="() => _editFontSize = size" />
                            <label class="form-check-label" for="font-@size">@size</label>
                        </div>
                    }
                </div>
            </div>

            <!-- Language -->
            <div class="mb-4">
                <label class="form-label fw-semibold">Language</label>
                <select class="form-select" style="max-width:300px;"
                        @bind="_editLanguage">
                    <option value="en">English</option>
                    <option value="es">Español</option>
                    <option value="fr">Français</option>
                    <option value="de">Deutsch</option>
                    <option value="ja">日本語</option>
                    <option value="zh">中文</option>
                    <option value="pt">Português</option>
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="setting-row mb-4">
                <div>
                    <div class="fw-semibold">Compact Mode</div>
                    <small class="text-muted">Reduce spacing and padding throughout the UI</small>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_editCompactMode"
                           @onchange="e => _editCompactMode = (bool)(e.Value ?? false)" />
                </div>
            </div>

            <!-- Live Preview -->
            <div class="mb-4">
                <label class="form-label fw-semibold">Preview</label>
                <div class="appearance-preview @GetPreviewClasses()">
                    <h5>Sample Heading</h5>
                    <p>This is a preview of your appearance settings. The selected theme, font size, and compact mode are reflected here.</p>
                    <div class="d-flex gap-2 mt-2">
                        <button class="btn btn-sm btn-primary">Primary</button>
                        <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                    </div>
                    <div class="mt-2">
                        <span class="badge bg-info">Badge</span>
                        <span class="badge bg-warning text-dark ms-1">Warning</span>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save
            </button>
        </section>;
}

@code {
    // ── Navigation ──
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;
    private bool _saving;

    // ── Toast ──
    private string? _toastMessage;
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // ── Profile state ──
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editAvatarUrl = "";
    private string _editBio = "";
    private string _profileDisplayName = "";

    // ── Notification state ──
    private bool _editEmailNotifications;
    private bool _editPushNotifications;
    private bool _editWeeklyDigest;
    private List<string> _editMutedChannels = new();
    private List<string> _allChannels = new() { "general", "announcements", "random", "engineering", "design", "marketing" };

    // ── Security state ──
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;

    // ── Appearance state ──
    private string _editTheme = "System";
    private string _editFontSize = "Medium";
    private string _editLanguage = "en";
    private bool _editCompactMode;

    protected override async Task OnInitializedAsync()
    {
        await LoadSection(_activeSection);
        _loading = false;
    }

    private async Task SetActiveSection(string section)
    {
        if (section == _activeSection) return;
        _activeSection = section;
        _loading = true;
        await LoadSection(section);
        _loading = false;
    }

    private async Task LoadSection(string section)
    {
        switch (section)
        {
            case "Profile":
                _savedProfile = await SettingsService.GetProfileAsync();
                ApplyProfile(_savedProfile);
                break;
            case "Notifications":
                var prefs = await SettingsService.GetNotificationPrefsAsync();
                _editEmailNotifications = prefs.EmailNotifications;
                _editPushNotifications = prefs.PushNotifications;
                _editWeeklyDigest = prefs.WeeklyDigest;
                _editMutedChannels = new List<string>(prefs.MutedChannels);
                break;
            case "Security":
                var security = await SettingsService.GetSecuritySettingsAsync();
                _twoFactorEnabled = security.TwoFactorEnabled;
                _lastPasswordChange = security.LastPasswordChange;
                _sessions = new List<ActiveSession>(security.Sessions);
                _passwordPanelOpen = false;
                _currentPassword = "";
                _newPassword = "";
                _confirmPassword = "";
                _passwordError = null;
                break;
            case "Appearance":
                var appearance = await SettingsService.GetAppearanceAsync();
                _editTheme = appearance.Theme;
                _editFontSize = appearance.FontSize;
                _editLanguage = appearance.Language;
                _editCompactMode = appearance.CompactMode;
                break;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        _editDisplayName = profile.DisplayName;
        _editEmail = profile.Email;
        _editAvatarUrl = profile.AvatarUrl;
        _editBio = profile.Bio;
        _profileDisplayName = profile.AvatarUrl;
    }

    // ── Profile actions ──
    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _profileDisplayName = _editAvatarUrl;
            ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save profile: {ex.Message}", isError: true);
        }
        finally { _saving = false; }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
    }

    // ── Notification actions ──
    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted && !_editMutedChannels.Contains(channel))
            _editMutedChannels.Add(channel);
        else if (!muted)
            _editMutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var prefs = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, new List<string>(_editMutedChannels));
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save preferences: {ex.Message}", isError: true);
        }
        finally { _saving = false; }
    }

    // ── Security actions ──
    private async Task ChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword) ||
            string.IsNullOrWhiteSpace(_confirmPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally { _saving = false; }
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.Remove(_sessionToRevoke);
            ShowToast($"Session on {_sessionToRevoke.Device} revoked.");
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to revoke session: {ex.Message}", isError: true);
        }
        finally { _saving = false; }
    }

    // ── Appearance actions ──
    private string GetPreviewClasses()
    {
        var classes = $"preview-theme-{_editTheme.ToLowerInvariant()} preview-font-{_editFontSize.ToLowerInvariant()}";
        if (_editCompactMode) classes += " preview-compact";
        return classes;
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save appearance: {ex.Message}", isError: true);
        }
        finally { _saving = false; }
    }

    // ── Toast helper ──
    private void ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastMessage = message;
        _toastIsError = isError;
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _ = Task.Run(async () =>
        {
            await Task.Delay(4000, token);
            if (!token.IsCancellationRequested)
            {
                await InvokeAsync(() =>
                {
                    _toastMessage = null;
                    StateHasChanged();
                });
            }
        }, token);
    }

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}
"}

